const modelosPorFabricante = {
  "Airbus": ["A319-100", "A320-200", "A321-200", "A330-200", "A330-300"],
  "ATR": ["ATR 42-300", "ATR 42-500", "ATR 72-200", "ATR 72-500"],
  "Boeing": ["B737-400", "B737-800"],
  "Cessna": ["Cessna 208B Grand Caravan"]
};

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>DOA Client Intake Form</title>
  <style>
    :root {
      --bg-1: #06131f;
      --bg-2: #10314b;
      --panel: rgba(255,255,255,0.96);
      --ink: #10202d;
      --muted: #5b6b79;
      --accent: #0f7b6c;
      --line: rgba(16,32,45,0.12);
    }
    * { box-sizing: border-box; }
    body { margin: 0; font-family: Georgia, 'Times New Roman', serif; background: radial-gradient(circle at top right, rgba(212,138,40,0.18), transparent 22%), linear-gradient(135deg, var(--bg-1), var(--bg-2)); color: var(--ink); min-height: 100vh; padding: 28px; }
    .shell { width: min(1120px, 100%); margin: 0 auto; background: var(--panel); border-radius: 28px; overflow: hidden; box-shadow: 0 28px 80px rgba(0,0,0,0.28); }
    .hero { padding: 42px 42px 28px; background: linear-gradient(160deg, rgba(6,19,31,0.98), rgba(12,34,52,0.94)); color: #f4efe6; }
    .eyebrow { text-transform: uppercase; letter-spacing: 0.18em; font-size: 12px; opacity: 0.78; margin-bottom: 16px; }
    h1 { margin: 0 0 12px; font-size: clamp(34px, 5vw, 52px); line-height: 0.95; }
    .hero p { margin: 0; max-width: 58ch; color: rgba(244,239,230,0.8); line-height: 1.65; font-size: 16px; }
    form { padding: 34px 42px 42px; display: grid; gap: 28px; }
    .section { display: grid; gap: 18px; padding-bottom: 10px; border-bottom: 1px solid var(--line); }
    .section:last-of-type { border-bottom: 0; padding-bottom: 0; }
    .section-title { display: flex; align-items: center; gap: 10px; font-size: 21px; font-weight: 700; }
    .section-title span { display: inline-grid; place-items: center; width: 32px; height: 32px; border-radius: 50%; background: rgba(15,123,108,0.12); color: var(--accent); font-size: 14px; }
    .grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 18px; }
    .full { grid-column: 1 / -1; }
    label { display: grid; gap: 8px; font-size: 14px; font-weight: 700; }
    .hint { color: var(--muted); font-size: 13px; line-height: 1.5; font-weight: 400; }
    .conditional { display: none; }
    .conditional.show { display: grid; }
    input, select, textarea, button { font: inherit; }
    input, select, textarea { width: 100%; border: 1px solid var(--line); border-radius: 14px; padding: 13px 14px; background: #fff; color: var(--ink); outline: none; }
    textarea { min-height: 150px; resize: vertical; }
    .footer { display: flex; align-items: center; justify-content: space-between; gap: 18px; margin-top: 10px; padding-top: 14px; border-top: 1px solid var(--line); }
    .footer p { margin: 0; color: var(--muted); font-size: 13px; line-height: 1.6; max-width: 52ch; }
    button { border: 0; border-radius: 999px; padding: 15px 24px; background: linear-gradient(135deg, var(--accent), #169785); color: white; font-weight: 700; cursor: pointer; }
    @media (max-width: 860px) { body { padding: 16px; } .hero, form { padding-left: 22px; padding-right: 22px; } .grid { grid-template-columns: 1fr; } .footer { flex-direction: column; align-items: stretch; } button { width: 100%; } }
  </style>
</head>
<body>
  <div class="shell">
    <section class="hero">
      <div class="eyebrow">Design Organisation Approval</div>
      <h1>Client Project Intake</h1>
      <p>Please complete this form so our DOA management team can identify your company, review the aircraft involved, and start the internal intake process for your request.</p>
    </section>
    <form id="doaClientForm" method="POST">
      <section class="section">
        <div class="section-title"><span>1</span>Company information</div>
        <div class="grid">
          <label class="full">Company name<input type="text" name="cliente_nombre" required placeholder="Legal or commercial company name" /></label>
          <label>VAT / Tax ID<input type="text" name="cliente_cif_vat" placeholder="Optional tax identifier" /></label>
          <label>Country<input type="text" name="cliente_pais" required placeholder="Country" /></label>
          <label>City<input type="text" name="cliente_ciudad" placeholder="City" /></label>
          <label class="full">Address<input type="text" name="cliente_direccion" placeholder="Company address" /></label>
          <label>Phone<input type="text" name="cliente_telefono" placeholder="Main company phone" /></label>
          <label>Website<input type="url" name="cliente_web" placeholder="https://company.com" /></label>
        </div>
      </section>
      <section class="section">
        <div class="section-title"><span>2</span>Main contact</div>
        <div class="grid">
          <label>First name<input type="text" name="contacto_nombre" required placeholder="Contact first name" /></label>
          <label>Last name<input type="text" name="contacto_apellidos" placeholder="Contact last name" /></label>
          <label>Email<input type="email" name="contacto_email" required placeholder="name@company.com" /></label>
          <label>Phone<input type="text" name="contacto_telefono" placeholder="Direct phone" /></label>
          <label class="full">Position / Role<input type="text" name="contacto_cargo" placeholder="Engineering Manager, CAMO, Technical Director..." /></label>
        </div>
      </section>
      <section class="section">
        <div class="section-title"><span>3</span>Project request</div>
        <div class="grid">
          <label>Aircraft manufacturer
            <select id="fabricante" name="fabricante" required onchange="window.renderModelos(this.value)">
              <option value="">Select a manufacturer</option>
              <option value="Airbus">Airbus</option>
              <option value="ATR">ATR</option>
              <option value="Boeing">Boeing</option>
              <option value="Cessna">Cessna</option>
              <option value="Other">Other</option>
            </select>
          </label>
          <label id="fabricante_otro_wrapper" class="conditional">Other manufacturer
            <input type="text" id="fabricante_otro" name="fabricante_otro" placeholder="Write the aircraft manufacturer" />
          </label>
          <label>Aircraft model
            <select id="modelo" name="modelo" required disabled>
              <option value="">Select a manufacturer first</option>
            </select>
          </label>
          <label id="modelo_otro_wrapper" class="conditional">Other model
            <input type="text" id="modelo_otro" name="modelo_otro" placeholder="Write the aircraft model" />
          </label>
          <label>Registration<input type="text" name="matricula" required placeholder="Example: EC-XXX" /></label>
          <label>Project type
            <select name="tipo_solicitud" required>
              <option value="">Select request type</option>
              <option value="nuevo_proyecto">New project</option>
              <option value="modificacion_existente">Modification to an existing project</option>
            </select>
          </label>
          <label class="full">Modification / request description
            <textarea name="descripcion_modificacion" required placeholder="Describe the requested modification or project scope with as much detail as possible."></textarea>
            <div class="hint">Include installation intent, cabin area, affected systems, available references or any constraints already known.</div>
          </label>
        </div>
      </section>
      <div class="footer">
        <p>By submitting this form, your request will be registered for internal intake. A member of the DOA management team will review the information and contact you if more detail is required.</p>
        <button type="submit">Submit request</button>
      </div>
    </form>
  </div>
  <script>
    window.modelosPorFabricante = ${JSON.stringify(modelosPorFabricante)};
    window.renderModelos = function(fabricante) {
      const modeloSelect = document.getElementById('modelo');
      const fabricanteOtroWrapper = document.getElementById('fabricante_otro_wrapper');
      const fabricanteOtroInput = document.getElementById('fabricante_otro');
      const modeloOtroWrapper = document.getElementById('modelo_otro_wrapper');
      const modeloOtroInput = document.getElementById('modelo_otro');
      fabricanteOtroWrapper.classList.toggle('show', fabricante === 'Other');
      fabricanteOtroInput.required = fabricante === 'Other';
      if (fabricante !== 'Other') fabricanteOtroInput.value = '';
      modeloSelect.innerHTML = '';
      if (fabricante === 'Other') {
        modeloSelect.disabled = true;
        modeloSelect.required = false;
        modeloSelect.innerHTML = '<option value="">Model written below</option>';
        modeloOtroWrapper.classList.add('show');
        modeloOtroInput.required = true;
        return;
      }
      const modelos = window.modelosPorFabricante[fabricante] || [];
      modeloOtroWrapper.classList.remove('show');
      modeloOtroInput.required = false;
      modeloOtroInput.value = '';
      modeloSelect.required = true;
      if (!modelos.length) {
        modeloSelect.disabled = true;
        modeloSelect.innerHTML = '<option value="">Select a manufacturer first</option>';
        return;
      }
      modeloSelect.disabled = false;
      modeloSelect.innerHTML = '<option value="">Select an aircraft model</option>';
      for (const modelo of modelos) {
        const option = document.createElement('option');
        option.value = modelo;
        option.textContent = modelo;
        modeloSelect.appendChild(option);
      }
      const otherOption = document.createElement('option');
      otherOption.value = 'Other';
      otherOption.textContent = 'Other';
      modeloSelect.appendChild(otherOption);
      modeloSelect.onchange = function() {
        const isOtherModel = this.value === 'Other';
        modeloOtroWrapper.classList.toggle('show', isOtherModel);
        modeloOtroInput.required = isOtherModel;
        if (!isOtherModel) modeloOtroInput.value = '';
      };
    };
    document.getElementById('doaClientForm').action = window.location.href.replace(/doa-formulario-cliente\\/?$/, 'doa-formulario-cliente-submit');
  </script>
</body>
</html>`;
return { json: { html } };

const body = $json.body || $json;
const clean = (value) => {
  const text = (value ?? '').toString().trim();
  return text || null;
};
const required = (value, label) => {
  const text = (value ?? '').toString().trim();
  if (!text) throw new Error(`Missing required field: ${label}`);
  return text;
};
const cliente = {
  nombre: required(body.cliente_nombre, 'cliente_nombre'),
  cif_vat: clean(body.cliente_cif_vat),
  pais: required(body.cliente_pais, 'cliente_pais'),
  ciudad: clean(body.cliente_ciudad),
  direccion: clean(body.cliente_direccion),
  telefono: clean(body.cliente_telefono),
  web: clean(body.cliente_web),
  activo: true,
  notas: null,
};
const fabricante = body.fabricante === 'Other'
  ? required(body.fabricante_otro, 'fabricante_otro')
  : required(body.fabricante, 'fabricante');
const modelo = body.fabricante === 'Other' || body.modelo === 'Other'
  ? required(body.modelo_otro, 'modelo_otro')
  : required(body.modelo, 'modelo');
const contacto = {
  nombre: required(body.contacto_nombre, 'contacto_nombre'),
  apellidos: clean(body.contacto_apellidos),
  email: required(body.contacto_email, 'contacto_email'),
  telefono: clean(body.contacto_telefono),
  cargo: clean(body.contacto_cargo),
  es_principal: true,
  activo: true,
};
const intake = {
  empresa: cliente.nombre,
  remitente: contacto.email,
  asunto: `Formulario web DOA - ${cliente.nombre} - ${modelo}`,
  cuerpo_original: [
    `Tipo de solicitud: ${required(body.tipo_solicitud, 'tipo_solicitud')}`,
    `Fabricante: ${fabricante}`,
    `Modelo: ${modelo}`,
    `Matricula: ${required(body.matricula, 'matricula')}`,
    `Descripcion: ${required(body.descripcion_modificacion, 'descripcion_modificacion')}`,
    '',
    `Empresa: ${cliente.nombre}`,
    `Pais: ${cliente.pais}`,
    `Ciudad: ${cliente.ciudad || ''}`,
    `Direccion: ${cliente.direccion || ''}`,
    `Telefono empresa: ${cliente.telefono || ''}`,
    `Web: ${cliente.web || ''}`,
    '',
    `Contacto: ${contacto.nombre} ${contacto.apellidos || ''}`.trim(),
    `Email contacto: ${contacto.email}`,
    `Telefono contacto: ${contacto.telefono || ''}`,
    `Cargo: ${contacto.cargo || ''}`,
  ].join('\n'),
  clasificacion: body.tipo_solicitud === 'modificacion_existente' ? 'Cliente solicita modificacion a proyecto existente' : 'Cliente solicita proyecto nuevo',
  respuesta_ia: '',
};
return { json: { cliente, contacto, intake } };

const createdClient = $json || {};
const payload = $('Preparar Payloads').item.json || {};
const cliente = (createdClient.id ? createdClient : (createdClient.data && createdClient.data[0]) ? createdClient.data[0] : null) || createdClient;
if (!cliente.id) throw new Error('No se pudo recuperar el id del cliente creado.');
return {
  json: {
    contacto: {
      cliente_id: cliente.id,
      nombre: payload.contacto.nombre,
      apellidos: payload.contacto.apellidos,
      email: payload.contacto.email,
      telefono: payload.contacto.telefono,
      cargo: payload.contacto.cargo,
      es_principal: true,
      activo: true,
    },
    intake: payload.intake,
    cliente: cliente,
  },
};

const cliente = $('Preparar Contacto').item.json.cliente || {};
const intake = $('Preparar Contacto').item.json.intake || {};
const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Request received</title>
  <style>
    body { margin:0; min-height:100vh; display:grid; place-items:center; padding:24px; background:linear-gradient(135deg,#071521,#143046); font-family:Georgia,'Times New Roman',serif; }
    .card { width:min(720px,100%); background:rgba(255,255,255,0.96); border-radius:24px; padding:34px; box-shadow:0 24px 70px rgba(0,0,0,0.28); color:#10202d; }
    h1 { margin:0 0 12px; font-size:36px; }
    p { color:#4f6170; line-height:1.6; }
    dl { display:grid; grid-template-columns: 190px 1fr; gap:10px 14px; margin-top:24px; }
    dt { font-weight:700; }
    dd { margin:0; }
    @media (max-width:640px){ dl { grid-template-columns:1fr; } }
  </style>
</head>
<body>
  <section class="card">
    <h1>Request received</h1>
    <p>Your project request has been registered successfully. The DOA management team will review the information and contact you if additional detail is required.</p>
    <dl>
      <dt>Company</dt><dd>${cliente.nombre || ''}</dd>
      <dt>Aircraft / Request</dt><dd>${intake.asunto || ''}</dd>
      <dt>Classification</dt><dd>${intake.clasificacion || ''}</dd>
    </dl>
  </section>
</body>
</html>`;
return { json: { html } };
